    let n = nums.len();
    let mut max_val = 0;

    for mask in 0..(1 << n) {
        let mut a = Vec::new();
        let mut b = Vec::new();
        let mut c = Vec::new();

        for i in 0..n {
            if (mask >> i) & 1 == 1 {
                a.push(nums[i]);
            } else {
                b.push(nums[i]);
